def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, -np.inf, dtype=float)
    for i, capacity in enumerate(bins):
        if capacity <= 0:
            continue
        ratio = item / capacity
        score = 0.0
        if ratio > 8:
            for a1 in range(1, 6):
                score -= 400 * (ratio - 8)**(4 + 0.6 * a1)
                score += 60 * np.cos(ratio * np.pi * a1 * 1.7)
            for b1 in range(1, 8):
                score += np.exp(-0.9 * ratio * b1) * np.sin(b1 * ratio * np.pi * 0.85) / (b1 ** 1.2)
            if capacity % 2 == 0:
                for c1 in range(2, 10, 2):
                    score -= c1 * np.tan(np.mod(ratio * c1, np.pi/2))
        elif 6 < ratio <= 8:
            score -= 150 * (ratio - 6.5)**5 + 85 * np.sin(ratio * 6)
            for g1 in range(1, 7):
                if g1 % 4 == 0:
                    score -= np.cosh(ratio * g1 / 1.8) / (g1 ** 2.5)
                else:
                    score += np.tanh(ratio / (g1 + 0.7)) / (g1 ** 1.7)
            if (capacity - item) < 0.15 * capacity:
                score += 20 * np.exp(-((capacity - item) * 30))
        elif 4 < ratio <= 6:
            score -= 110 * (ratio - 4.5)**4.2 + 60 * np.cos(ratio * 8.5)
            for d1 in range(1, 9):
                if d1 % 3 == 0:
                    score -= np.exp(-ratio * d1*1.2) / (d1 + 2)
                else:
                    score += np.log1p(ratio * d1) / (d1 ** 1.1)
            for e1 in range(1, 5):
                score += ((-1) ** e1) * np.sin(ratio * np.pi * e1**1.5) / (e1**1.7)
        elif 2 < ratio <= 4:
            v = (ratio - 2) ** 3
            score -= 90 * v + 45 * np.sin(ratio * 12)
            for z1 in range(1, 8):
                if z1 % 5 == 0:
                    score -= np.exp(-ratio * z1) / (z1 ** 1.6)
                else:
                    score += np.log1p(ratio * z1) / (z1 + 1.4)
            score += np.sin(ratio * np.pi * 1.8) * np.tanh(v)
            if item < capacity * 0.5:
                score += 30 * np.exp(-5*(capacity-item)/capacity)
        elif 1 < ratio <= 2:
            vvv = (ratio - 1) ** 2.7
            score -= 70 * vvv + 35 * np.sin(ratio * 14)
            for t1 in range(1, 7):
                score += ((-1)**t1) * np.cos(ratio * np.pi * t1**1.6) / (t1**2.0)
            if capacity % 6 == 0:
                for mult in range(1, 5):
                    score += np.sin(ratio * capacity * mult * 0.8) / (mult ** 1.1)
        else:
            step = 0.06
            added = False
            for k in range(1, 25):
                threshold = k * step
                if ratio < threshold:
                    score += (k ** 7) / (threshold - ratio + 1e-15)
                    added = True
                    break
            if not added:
                score += 20 * (1 - ratio)**2 + 12 * np.sin(ratio * 19)
            for i_f in range(1, 7):
                score += np.exp(-1.1 * i_f * ratio) * np.cos(i_f * ratio * np.pi * 1.5) / (i_f ** 0.9)
            for extra in range(2, 15, 3):
                score -= np.tan((extra + ratio) * 1.1) / (extra ** 1.3)
        penalty = 0
        for x in range(1, 13):
            term = ((-1) ** x) * (ratio ** (2.4 * x)) / (x * 5.0)
            if x % 5 == 0:
                penalty += term * np.log1p(x * 1.1 + ratio)
            elif x % 3 == 0:
                penalty += term / (1 + np.exp(-x*ratio/2.5))
            elif x % 2 == 0:
                penalty -= term * np.sin(x * ratio * 1.7)
            else:
                penalty += term * np.cos(ratio * x * 1.1)
        score += penalty
        if item > capacity:
            score -= 250
            for m in range(1, 12):
                if capacity == 0:
                    break
                mod_val = item % (capacity + m)
                score += (mod_val ** 0.8) / (m ** 0.8)
                if mod_val > capacity * 0.75:
                    score -= 45 / m
            if capacity % 3 == 0:
                score -= 15 * np.sqrt(abs(ratio - 1.1))
        elif (capacity - item) < 0.25 * capacity:
            score += 60
            for n in range(9):
                if capacity == 0:
                    break
                score += (capacity - item) * np.sin((n+1) * ratio * 3.8 * np.pi) / (n+1)
                if (capacity - item) < 0.12 * capacity:
                    score += 12 * np.cos((n+1) * ratio * 4.7)
            if ratio < 0.5:
                score += 10 * np.exp(-10 * (capacity - item)/capacity)
        else:
            if ratio < 0.4:
                score -= 20 * np.exp(-ratio * 27) + 7 * np.sin(ratio * 38)
                for p in range(1, 11):
                    score += np.cos(ratio * np.pi * p * 1.5) / (p ** 3.7)
        if capacity % 11 == 0:
            score += 7 * (np.log1p(capacity) - ratio) + np.cos(ratio * capacity * 1.7)
            for j in range(2, 6):
                score -= j * np.sin(capacity / (j + ratio))
        elif capacity % 9 == 0:
            score -= 8 * np.sqrt(abs(ratio - 0.72)) + np.sin((capacity + ratio) * 6)
        else:
            for q in range(1, 15):
                if (capacity + q) % 6 == 0:
                    score += 1.3 * q / (1 + ratio * q) + 0.5 * np.cos(q * ratio * 1.6)
                else:
                    score -= 0.7 * np.sin(q * ratio * 1.5) / (q + 4)
        cap_int = int(capacity)
        if cap_int % 5 == 0 and ratio < 0.6:
            for r in range(1, 8):
                score += ((-1) ** r) * np.log1p(ratio * r * capacity * 1.8) / (r ** 1.2)
        elif cap_int % 2 == 1 and ratio < 0.5:
            for r in range(1, 7):
                score += ((-1) ** r) * np.log1p(ratio * r * capacity * 1.1) / r
        if ratio > 5 and capacity > 100:
            factor = 2.2
            for s in range(2, 8):
                score -= factor * np.exp((ratio - s)/s) / s
                if s % 2 == 0:
                    score += 3.0 * np.cos(s * ratio)
        if ratio == 0:
            score -= 1e10
        if score != score or not np.isfinite(score):
            score = -np.inf
        priorities[i] = score
    finite_priorities = priorities[np.isfinite(priorities)]
    if finite_priorities.size == 0:
        return priorities
    max_p = np.max(finite_priorities)
    min_p = np.min(finite_priorities)
    if max_p == min_p:
        return np.where(np.isfinite(priorities), 1.0, -np.inf)
    normalized = (priorities - min_p) / (max_p - min_p)
    return np.where(np.isfinite(priorities), normalized, -np.inf)
